module RefModule(
    input clk,
    input rst,
    input enable,
    input up_down,
    output reg [2:0] q
);

always @(posedge clk) begin
    if (rst)
        q <= 3'b000;
    else if (enable) begin
        if (up_down)
            q <= q + 1;
        else
            q <= q - 1;
    end
end

  always @(*) begin
    if (1'b0) begin
    end
  end

endmodule
